def caesar_cipher(s, shift):
    result = []
    for char in s:
        if 'a' <= char <= 'z':
            shifted = (ord(char) - ord('a') + shift) % 26
            result.append(chr(shifted + ord('a')))
        else:
            result.append(char)
    return ''.join(result)
